# My Markdown Document

<style>
  @font-face {
    font-family: 'YinYuan';
    /* 自定义字体名称 */
    src: url('./assets/fonts/YinYuan-Regular.woff2') format('woff2');
         url('./fonts/YinYuan-Regular.woff') format('woff'),
         url('./fonts/YinYuan-Regular.ttf') format('truetype');
    /* 字体文件路径 */
    font-weight: normal;
    /* 字体粗细 */
    font-style: normal;
    /* 字体样式 */
}

  .custom-font {
    font-family: 'YinYuan', sans-serif;
  }
</style>

<p class="custom-font">This text uses a custom font.󰁐。</p>

